mapper.select:
SELECT FROM t_recipe r LEFT JOIN t_user u ON u.user_id = r.created_by LEFT JOIN t_recipe_rating rr ON rr.recipe_id = r.recipe_id LEFT JOIN t_recipe_rating_log rl ON rl.recipe_id = r.recipe_id AND rl.user_id = #{userId} WHERE r.recipe_status = 0
AND (r.is_admin_recommend = 1 OR r.created_by = #{userId})
AND r.food_name LIKE CONCAT('%', #{keyword}, '%')
AND r.meal_type = #{mealType}
ORDER BY r.is_admin_recommend DESC, r.last_change_time DESC, r.recipe_id DESC LIMIT #{limit}
